mapper.select:
SELECT ea.id, ea.title, ea.type, ea.summary, ea.expert_name as expertName, ea.view_count as viewCount, ea.thumb_count as thumbCount, ea.create_time as createTime FROM expert_analysis ea WHERE ea.deleted = 0 AND ea.status = 1
AND ea.expert_id = #{expertId}
AND ea.type = #{type}
ORDER BY ea.create_time DESC
